mapper.update:
update user_behavior
behavior_type = #{behaviorType}, target_id = #{targetId}, target_type = #{targetType}, content = #{content},
where behavior_id = #{behaviorId}

mapper.select:
select behavior_type as type, count(*) as cnt
from user_behavior where create_time between #{startDate} and #{endDate}
group by behavior_type order by cnt desc

choose.when:
select date(create_time) as date, count(*) as cnt
from user_behavior where create_time between #{startDate} and #{endDate}
group by date(create_time)

choose.otherwise:
select date_format(create_time, '%Y-%u') as week, count(*) as cnt
from user_behavior where create_time between #{startDate} and #{endDate}
group by date_format(create_time, '%Y-%u')
